// SILK stereo integration tests.
//
// Tests the Opus encoder and decoder stereo paths at 16kHz VOIP mode:
//   - Decode C reference stereo packets with the Rust decoder
//   - Encode stereo signals with the Rust encoder at VOIP mode

mod common;
//   - Decode and verify valid stereo output
//   - Test that stereo packets differ from mono packets
//   - Test L/R channel separation (left-only and right-only signals)
//
// C reference packets were generated by gen_stereo_vectors.c using the
// C libopus encoder at 16kHz stereo, VOIP mode, 32kbps, complexity 5,
// max bandwidth restricted to wideband.
//
// To regenerate:
//   gcc -O2 -I/home/ct37/projects/opus/include \
//       -o /tmp/gen_stereo /tmp/gen_stereo_vectors.c \
//       /home/ct37/projects/opus/build/libopus.a -lm
//   /tmp/gen_stereo > /tmp/stereo_vectors.txt
//
// Then paste the output into the C_STEREO_* constants below.

use opus::{
    Application, Bandwidth, Bitrate, Channels, OpusDecoder, OpusEncoder, SampleRate, Signal,
    opus_packet_get_nb_channels,
};

// =========================================================================
// C reference stereo packets (16kHz stereo, VOIP, 32kbps, complexity 5)
// Generated from the C libopus reference encoder.
// Each is the last packet after encoding 10 frames of 320 stereo samples.
//
// IMPORTANT: These must be regenerated by compiling and running
// /tmp/gen_stereo_vectors.c, then pasting the output here.
// =========================================================================

// C reference: stereo sine 440Hz left + 880Hz right, 32kbps
// Stereo TOC byte has bit 2 set (0x04 OR'd in).
// At 16kHz VOIP 32kbps, the mode decision picks SILK+CELT hybrid or SILK
// depending on bandwidth. With max_bandwidth = wideband, this forces SILK-only.
// The TOC for SILK WB stereo 20ms = (1<<5) | (0<<3) | 0x04 = 0x24.
// However the C encoder may pick NB stereo = 0x04.
// We accept any valid stereo SILK packet.
const C_STEREO_SINE_440L_880R: &[u8] = &[
    // PLACEHOLDER: paste output of gen_stereo_vectors for C_STEREO_SINE_440L_880R
    0x24, 0x00,
];

// C reference: mono-collapsed stereo (same 440Hz on both channels)
const C_STEREO_MONO_COLLAPSED: &[u8] = &[
    // PLACEHOLDER: paste output of gen_stereo_vectors for C_STEREO_MONO_COLLAPSED
    0x24, 0x00,
];

// C reference: stereo silence
const C_STEREO_SILENCE: &[u8] = &[
    // PLACEHOLDER: paste output of gen_stereo_vectors for C_STEREO_SILENCE
    0x24, 0x00,
];

// C reference: left-only (440Hz left, silence right)
const C_STEREO_LEFT_ONLY: &[u8] = &[
    // PLACEHOLDER: paste output of gen_stereo_vectors for C_STEREO_LEFT_ONLY
    0x24, 0x00,
];

// C reference: right-only (440Hz right, silence left)
const C_STEREO_RIGHT_ONLY: &[u8] = &[
    // PLACEHOLDER: paste output of gen_stereo_vectors for C_STEREO_RIGHT_ONLY
    0x24, 0x00,
];

// C reference: mono (1-channel) 440Hz for stereo-vs-mono comparison
#[allow(dead_code)]
const C_STEREO_MONO_440HZ: &[u8] = &[
    // PLACEHOLDER: paste output of gen_stereo_vectors for C_STEREO_MONO_440HZ
    0x20, 0x00,
];

// =========================================================================
// Constants
// =========================================================================

const SAMPLE_RATE: i32 = 16000;
const FRAME_SIZE: usize = 320; // 20ms at 16kHz
const FRAME_SIZE_10MS: usize = 160; // 10ms at 16kHz
const STEREO_FRAME: usize = FRAME_SIZE * 2; // interleaved L/R
const STEREO_FRAME_10MS: usize = FRAME_SIZE_10MS * 2; // interleaved L/R, 10ms
const BITRATE: i32 = 20000; // Low enough to trigger SILK/Hybrid mode for stereo
const COMPLEXITY: i32 = 5;
const NUM_WARMUP_FRAMES: usize = 10;

// =========================================================================
// Signal generation helpers
// =========================================================================

/// Generate a stereo interleaved sine: freq_l on left channel, freq_r on right channel.
fn generate_stereo_sine(
    freq_l: f32,
    freq_r: f32,
    amplitude: f32,
    num_samples: usize,
    sample_offset: usize,
) -> Vec<f32> {
    let mut buf = vec![0.0f32; num_samples * 2];
    for i in 0..num_samples {
        let t = (sample_offset + i) as f32 / SAMPLE_RATE as f32;
        buf[2 * i] = amplitude * (2.0 * std::f32::consts::PI * freq_l * t).sin();
        buf[2 * i + 1] = amplitude * (2.0 * std::f32::consts::PI * freq_r * t).sin();
    }
    buf
}

/// Generate mono-collapsed stereo: same sine on both channels.
fn generate_mono_collapsed(
    freq: f32,
    amplitude: f32,
    num_samples: usize,
    sample_offset: usize,
) -> Vec<f32> {
    let mut buf = vec![0.0f32; num_samples * 2];
    for i in 0..num_samples {
        let t = (sample_offset + i) as f32 / SAMPLE_RATE as f32;
        let val = amplitude * (2.0 * std::f32::consts::PI * freq * t).sin();
        buf[2 * i] = val;
        buf[2 * i + 1] = val;
    }
    buf
}

/// Generate left-only stereo: sine on left, silence on right.
fn generate_left_only(
    freq: f32,
    amplitude: f32,
    num_samples: usize,
    sample_offset: usize,
) -> Vec<f32> {
    let mut buf = vec![0.0f32; num_samples * 2];
    for i in 0..num_samples {
        let t = (sample_offset + i) as f32 / SAMPLE_RATE as f32;
        buf[2 * i] = amplitude * (2.0 * std::f32::consts::PI * freq * t).sin();
        buf[2 * i + 1] = 0.0;
    }
    buf
}

/// Generate right-only stereo: silence on left, sine on right.
fn generate_right_only(
    freq: f32,
    amplitude: f32,
    num_samples: usize,
    sample_offset: usize,
) -> Vec<f32> {
    let mut buf = vec![0.0f32; num_samples * 2];
    for i in 0..num_samples {
        let t = (sample_offset + i) as f32 / SAMPLE_RATE as f32;
        buf[2 * i] = 0.0;
        buf[2 * i + 1] = amplitude * (2.0 * std::f32::consts::PI * freq * t).sin();
    }
    buf
}

/// Generate stereo silence.
fn generate_stereo_silence(num_samples: usize) -> Vec<f32> {
    vec![0.0f32; num_samples * 2]
}

/// Generate a mono sine (single-channel).
fn generate_mono_sine(
    freq: f32,
    amplitude: f32,
    num_samples: usize,
    sample_offset: usize,
) -> Vec<f32> {
    let mut buf = vec![0.0f32; num_samples];
    for (i, sample) in buf.iter_mut().enumerate() {
        let t = (sample_offset + i) as f32 / SAMPLE_RATE as f32;
        *sample = amplitude * (2.0 * std::f32::consts::PI * freq * t).sin();
    }
    buf
}

use common::total_energy;

/// Compute RMS energy of a PCM buffer.
use common::rms as rms_energy;

/// Extract left-channel samples from interleaved stereo PCM.
fn left_channel(pcm: &[f32]) -> Vec<f32> {
    pcm.chunks(2).map(|c| c[0]).collect()
}

/// Extract right-channel samples from interleaved stereo PCM.
fn right_channel(pcm: &[f32]) -> Vec<f32> {
    pcm.chunks(2).map(|c| c[1]).collect()
}

use common::count_differing_bytes;

// =========================================================================
// Helper: create encoder, encode N frames, return all packets
// =========================================================================

/// Create a stereo encoder configured for SILK stereo testing.
fn create_stereo_encoder() -> OpusEncoder {
    let mut enc =
        OpusEncoder::new(SampleRate::Hz16000, Channels::Stereo, Application::Voip).unwrap();
    enc.set_bitrate(Bitrate::BitsPerSecond(BITRATE));
    enc.set_complexity(COMPLEXITY);
    enc.set_signal(Signal::Voice);
    // Don't set bandwidth explicitly — let the encoder choose SILK/Hybrid based on bitrate
    enc
}

/// Create a mono encoder with the same settings (for comparison).
fn create_mono_encoder() -> OpusEncoder {
    let mut enc = OpusEncoder::new(SampleRate::Hz16000, Channels::Mono, Application::Voip).unwrap();
    enc.set_bitrate(Bitrate::BitsPerSecond(BITRATE));
    enc.set_complexity(COMPLEXITY);
    enc.set_bandwidth(Bandwidth::Wideband);
    enc
}

/// Encode multiple stereo frames at the given frame size, returning all packets.
fn encode_stereo_frames_with_size(
    enc: &mut OpusEncoder,
    generate_frame: &dyn Fn(usize) -> Vec<f32>,
    num_frames: usize,
    frame_size: usize,
) -> Vec<Vec<u8>> {
    let expected_len = frame_size * 2; // interleaved L/R
    let mut packets = Vec::new();
    for frame_idx in 0..num_frames {
        let input = generate_frame(frame_idx);
        assert_eq!(
            input.len(),
            expected_len,
            "Stereo frame must have {} samples",
            expected_len
        );
        let mut packet = vec![0u8; 1500];
        let nbytes = enc
            .encode_float(&input, frame_size as i32, &mut packet, 1500)
            .expect("Stereo encode should succeed");
        assert!(
            nbytes > 0,
            "Encode should produce bytes at frame {}",
            frame_idx
        );
        packet.truncate(nbytes as usize);
        packets.push(packet);
    }
    packets
}

/// Encode multiple 20ms stereo frames, returning all packets.
fn encode_stereo_frames(
    enc: &mut OpusEncoder,
    generate_frame: &dyn Fn(usize) -> Vec<f32>,
    num_frames: usize,
) -> Vec<Vec<u8>> {
    encode_stereo_frames_with_size(enc, generate_frame, num_frames, FRAME_SIZE)
}

/// Encode multiple mono frames, returning all packets.
fn encode_mono_frames(
    enc: &mut OpusEncoder,
    generate_frame: &dyn Fn(usize) -> Vec<f32>,
    num_frames: usize,
) -> Vec<Vec<u8>> {
    let mut packets = Vec::new();
    for frame_idx in 0..num_frames {
        let input = generate_frame(frame_idx);
        assert_eq!(
            input.len(),
            FRAME_SIZE,
            "Mono frame must have {} samples",
            FRAME_SIZE
        );
        let mut packet = vec![0u8; 1500];
        let nbytes = enc
            .encode_float(&input, FRAME_SIZE as i32, &mut packet, 1500)
            .expect("Mono encode should succeed");
        assert!(
            nbytes > 0,
            "Mono encode should produce bytes at frame {}",
            frame_idx
        );
        packet.truncate(nbytes as usize);
        packets.push(packet);
    }
    packets
}

/// Decode all packets with a stereo decoder, returning all decoded PCM concatenated.
fn decode_all_stereo(packets: &[Vec<u8>]) -> Vec<f32> {
    let mut dec = OpusDecoder::new(SampleRate::Hz16000, Channels::Stereo).unwrap();
    let mut all_pcm = Vec::new();
    for pkt in packets {
        let mut pcm = vec![0.0f32; STEREO_FRAME];
        let n = dec
            .decode_float(Some(pkt), &mut pcm, FRAME_SIZE as i32, false)
            .expect("Decode should succeed");
        all_pcm.extend_from_slice(&pcm[..n as usize * 2]);
    }
    all_pcm
}

