// Tests 3: Decode and verify valid stereo output
// =========================================================================

#[test]
fn test_stereo_roundtrip_sine_440l_880r() {
    let mut enc = create_stereo_encoder();
    let packets = encode_stereo_frames(
        &mut enc,
        &|frame_idx| generate_stereo_sine(440.0, 880.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    // Decode all packets
    let mut dec = OpusDecoder::new(SampleRate::Hz16000, Channels::Stereo).unwrap();
    let mut last_pcm = vec![0.0f32; STEREO_FRAME];
    for pkt in &packets {
        let mut pcm = vec![0.0f32; STEREO_FRAME];
        let result = dec.decode_float(Some(pkt), &mut pcm, FRAME_SIZE as i32, false);
        assert!(result.is_ok(), "Stereo decode should succeed: {:?}", result);
        let n = result.unwrap() as usize;
        assert_eq!(
            n, FRAME_SIZE,
            "Should decode exactly {} samples",
            FRAME_SIZE
        );
        last_pcm = pcm;
    }

    // The last decoded frame should have non-trivial energy on both channels
    let left = left_channel(&last_pcm);
    let right = right_channel(&last_pcm);
    let left_energy = total_energy(&left);
    let right_energy = total_energy(&right);

    println!(
        "  Stereo sine roundtrip: left energy = {:.6}, right energy = {:.6}",
        left_energy, right_energy
    );

    assert!(
        left_energy > 1e-6,
        "Left channel should have audible energy after roundtrip, got {:.8}",
        left_energy
    );
    assert!(
        right_energy > 1e-6,
        "Right channel should have audible energy after roundtrip, got {:.8}",
        right_energy
    );
}

#[test]
fn test_stereo_roundtrip_silence() {
    let mut enc = create_stereo_encoder();
    let packets = encode_stereo_frames(
        &mut enc,
        &|_| generate_stereo_silence(FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    let mut dec = OpusDecoder::new(SampleRate::Hz16000, Channels::Stereo).unwrap();
    let mut last_pcm = vec![0.0f32; STEREO_FRAME];
    for pkt in &packets {
        let mut pcm = vec![0.0f32; STEREO_FRAME];
        let result = dec.decode_float(Some(pkt), &mut pcm, FRAME_SIZE as i32, false);
        assert!(
            result.is_ok(),
            "Silence decode should succeed: {:?}",
            result
        );
        last_pcm = pcm;
    }

    let energy = rms_energy(&last_pcm);
    println!("  Stereo silence roundtrip: RMS energy = {:.8}", energy);
    assert!(
        energy < 2.0,
        "Stereo silence should decode to low energy, got RMS {:.8}",
        energy
    );
}

#[test]
fn test_stereo_roundtrip_mono_collapsed() {
    let mut enc = create_stereo_encoder();
    let packets = encode_stereo_frames(
        &mut enc,
        &|frame_idx| generate_mono_collapsed(440.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    let mut dec = OpusDecoder::new(SampleRate::Hz16000, Channels::Stereo).unwrap();
    let mut last_pcm = vec![0.0f32; STEREO_FRAME];
    for pkt in &packets {
        let mut pcm = vec![0.0f32; STEREO_FRAME];
        dec.decode_float(Some(pkt), &mut pcm, FRAME_SIZE as i32, false)
            .expect("Mono-collapsed decode should succeed");
        last_pcm = pcm;
    }

    // Both channels should have similar energy (same signal)
    let left = left_channel(&last_pcm);
    let right = right_channel(&last_pcm);
    let left_energy = total_energy(&left);
    let right_energy = total_energy(&right);

    println!(
        "  Mono-collapsed roundtrip: left = {:.6}, right = {:.6}",
        left_energy, right_energy
    );

    // Both channels should be audible
    assert!(
        left_energy > 1e-6,
        "Left should be audible: {:.8}",
        left_energy
    );
    assert!(
        right_energy > 1e-6,
        "Right should be audible: {:.8}",
        right_energy
    );

    // For mono-collapsed input, L and R should be similar (within 20 dB)
    if left_energy > 1e-6 && right_energy > 1e-6 {
        let ratio = left_energy / right_energy;
        assert!(
            ratio > 0.01 && ratio < 100.0,
            "Mono-collapsed L/R energy ratio should be close to 1, got {:.4}",
            ratio
        );
    }
}

#[test]
fn test_stereo_output_is_finite() {
    let mut enc = create_stereo_encoder();
    let packets = encode_stereo_frames(
        &mut enc,
        &|frame_idx| generate_stereo_sine(440.0, 880.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    let mut dec = OpusDecoder::new(SampleRate::Hz16000, Channels::Stereo).unwrap();
    for (frame_idx, pkt) in packets.iter().enumerate() {
        let mut pcm = vec![0.0f32; STEREO_FRAME];
        dec.decode_float(Some(pkt), &mut pcm, FRAME_SIZE as i32, false)
            .expect("Decode should succeed");
        for (j, &sample) in pcm.iter().enumerate() {
            assert!(
                sample.is_finite(),
                "Frame {frame_idx}, sample {j}: got non-finite value {sample}"
            );
        }
    }
}

// =========================================================================
// Tests 4: Stereo packets differ from mono packets
// =========================================================================

#[test]
fn test_stereo_packets_differ_from_mono_packets() {
    // Encode the same 440Hz signal as stereo (both channels) and as mono
    let mut stereo_enc = create_stereo_encoder();
    let stereo_packets = encode_stereo_frames(
        &mut stereo_enc,
        &|frame_idx| generate_mono_collapsed(440.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    let mut mono_enc = create_mono_encoder();
    let mono_packets = encode_mono_frames(
        &mut mono_enc,
        &|frame_idx| generate_mono_sine(440.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    let stereo_last = stereo_packets.last().unwrap();
    let mono_last = mono_packets.last().unwrap();

    println!("  Stereo packet: {} bytes", stereo_last.len());
    println!("  Mono packet:   {} bytes", mono_last.len());

    // Stereo and mono packets must differ
    assert_ne!(
        stereo_last, mono_last,
        "Stereo and mono packets should differ even with the same signal content"
    );

    // The TOC byte should indicate different channel counts.
    // In Opus, the stereo bit is bit 2 of the TOC byte.
    let stereo_toc = stereo_last[0];
    let mono_toc = mono_last[0];
    let stereo_ch = opus_packet_get_nb_channels(stereo_last);
    let mono_ch = opus_packet_get_nb_channels(mono_last);

    println!(
        "  Stereo TOC: 0x{:02x} (channels={})",
        stereo_toc, stereo_ch
    );
    println!("  Mono TOC:   0x{:02x} (channels={})", mono_toc, mono_ch);

    assert_eq!(stereo_ch, 2, "Stereo packet should report 2 channels");
    assert_eq!(mono_ch, 1, "Mono packet should report 1 channel");

    // The stereo bit (bit 2) should be set in the stereo TOC
    assert!(
        stereo_toc & 0x04 != 0,
        "Stereo TOC byte 0x{:02x} should have bit 2 set",
        stereo_toc
    );
    // The stereo bit should NOT be set in the mono TOC
    assert!(
        mono_toc & 0x04 == 0,
        "Mono TOC byte 0x{:02x} should not have bit 2 set",
        mono_toc
    );
}

#[test]
fn test_stereo_vs_mono_payload_differs() {
    let mut stereo_enc = create_stereo_encoder();
    let stereo_packets = encode_stereo_frames(
        &mut stereo_enc,
        &|frame_idx| generate_mono_collapsed(440.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    let mut mono_enc = create_mono_encoder();
    let mono_packets = encode_mono_frames(
        &mut mono_enc,
        &|frame_idx| generate_mono_sine(440.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    // Compare multiple steady-state frames, not just the last
    for i in (NUM_WARMUP_FRAMES - 3)..NUM_WARMUP_FRAMES {
        let stereo_pkt = &stereo_packets[i];
        let mono_pkt = &mono_packets[i];

        assert_ne!(
            stereo_pkt, mono_pkt,
            "Frame {i}: stereo and mono packets should differ"
        );

        let diff = count_differing_bytes(stereo_pkt, mono_pkt);
        assert!(
            diff > 1,
            "Frame {i}: stereo vs mono should have multiple differing bytes, got {diff}"
        );
    }
}

