#[test]
fn test_stereo_encoder_produces_stereo_toc() {
    let mut enc = create_stereo_encoder();
    let packets = encode_stereo_frames(
        &mut enc,
        &|frame_idx| generate_stereo_sine(440.0, 880.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        NUM_WARMUP_FRAMES,
    );

    for (i, pkt) in packets.iter().enumerate() {
        let channels = opus_packet_get_nb_channels(pkt);
        assert_eq!(
            channels, 2,
            "Frame {i}: stereo encoder should produce 2-channel packets, got {channels}"
        );

        // TOC byte bit 2 must be set for stereo
        let toc = pkt[0];
        assert!(
            toc & 0x04 != 0,
            "Frame {i}: TOC byte 0x{:02x} should have stereo bit set",
            toc
        );
    }
}

#[test]
fn test_stereo_multiframe_roundtrip() {
    let mut enc = create_stereo_encoder();
    let mut dec = OpusDecoder::new(SampleRate::Hz16000, Channels::Stereo).unwrap();

    for frame in 0..15 {
        // Vary the signal: different frequencies on each channel across frames
        let freq_l = 200.0 + frame as f32 * 40.0;
        let freq_r = 400.0 + frame as f32 * 60.0;
        let amp = if frame == 7 { 0.0 } else { 0.3 }; // silence at frame 7

        let input = generate_stereo_sine(freq_l, freq_r, amp, FRAME_SIZE, frame * FRAME_SIZE);
        let mut packet = vec![0u8; 1500];
        let nbytes = enc
            .encode_float(&input, FRAME_SIZE as i32, &mut packet, 1500)
            .expect("Encode should succeed");
        assert!(nbytes > 0, "Frame {frame}: encode should produce bytes");

        let mut output = vec![0.0f32; STEREO_FRAME];
        let result = dec.decode_float(
            Some(&packet[..nbytes as usize]),
            &mut output,
            FRAME_SIZE as i32,
            false,
        );
        assert!(result.is_ok(), "Frame {frame}: decode failed: {:?}", result);

        // All samples must be finite
        for &s in &output {
            assert!(
                s.is_finite(),
                "Frame {frame}: non-finite sample in decode output"
            );
        }
    }
}

#[test]
fn test_stereo_packet_sizes_stable() {
    let mut enc = create_stereo_encoder();
    let packets = encode_stereo_frames(
        &mut enc,
        &|frame_idx| generate_stereo_sine(440.0, 880.0, 0.4, FRAME_SIZE, frame_idx * FRAME_SIZE),
        15,
    );

    // After warmup (first 5 frames), packet sizes should be relatively stable
    let stable_sizes: Vec<usize> = packets[5..].iter().map(|p| p.len()).collect();
    let avg = stable_sizes.iter().sum::<usize>() as f64 / stable_sizes.len() as f64;

    println!("  Stereo packet sizes (frames 5+): {:?}", stable_sizes);
    println!("  Average: {avg:.1} bytes");

    for (i, &sz) in stable_sizes.iter().enumerate() {
        assert!(
            (2..=1275).contains(&sz),
            "Frame {} stereo packet size {} is out of expected range",
            5 + i,
            sz
        );
    }

    let min_sz = *stable_sizes.iter().min().unwrap();
    let max_sz = *stable_sizes.iter().max().unwrap();
    if min_sz > 0 {
        let ratio = max_sz as f64 / min_sz as f64;
        assert!(
            ratio < 5.0,
            "Stereo packet sizes should be stable: min={min_sz} max={max_sz} ratio={ratio:.2}"
        );
    }
}

